package inequivalent;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair83Method2Test {

    private final ClonePair83 subject = new ClonePair83();

    @Test
    void method2FindsExactCaseSensitiveMatch() {
        // Generated by Codex (gpt-5.4).
        char[] source = "abracadabra".toCharArray();
        char[] target = "cad".toCharArray();

        assertEquals(4, subject.method2(source, 0, source.length, target, 0, target.length, 0));
    }

    @Test
    void method2DoesNotIgnoreCase() {
        // Generated by Codex (gpt-5.4).
        char[] source = "abRaCadabra".toCharArray();
        char[] target = "cAD".toCharArray();

        assertEquals(-1, subject.method2(source, 0, source.length, target, 0, target.length, 0));
    }

    @Test
    void method2NormalizesNegativeFromIndexToZero() {
        // Generated by Codex (gpt-5.4).
        char[] source = "hello".toCharArray();
        char[] target = "he".toCharArray();

        assertEquals(0, subject.method2(source, 0, source.length, target, 0, target.length, -4));
    }

    @Test
    void method2ReturnsSourceCountWhenFromIndexIsPastEndAndTargetIsEmpty() {
        // Generated by Codex (gpt-5.4).
        char[] source = "hello".toCharArray();
        char[] target = "x".toCharArray();

        assertEquals(source.length, subject.method2(source, 0, source.length, target, 0, 0, source.length));
    }

    @Test
    void method2ThrowsNullPointerExceptionWhenSourceIsNullAndSearchMustProceed() {
        // Generated by Codex (gpt-5.4).
        char[] target = "he".toCharArray();

        assertThrows(NullPointerException.class, () -> subject.method2(null, 0, 3, target, 0, target.length, 0));
    }
}
